/**
 * Results Panel Component
 * Displays formatted JSON results from API responses
 */

import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-results-panel',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="results-panel">
      <div class="results-header">
        <h3>Results</h3>
        <button class="btn-copy" (click)="copyToClipboard()" title="Copy results">
          📋 Copy
        </button>
      </div>
      <pre class="results-content">{{ formatResults() }}</pre>
    </div>
  `,
  styles: [`
    .results-panel {
      background: #f5f5f5;
      border: 1px solid #ddd;
      border-radius: 4px;
      padding: 15px;
      margin-top: 20px;
    }

    .results-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 10px;
      border-bottom: 1px solid #ddd;
      padding-bottom: 10px;
    }

    .results-header h3 {
      margin: 0;
      color: #333;
    }

    .btn-copy {
      padding: 5px 10px;
      background: white;
      border: 1px solid #ddd;
      border-radius: 3px;
      cursor: pointer;
      font-size: 12px;
      transition: all 0.2s;
    }

    .btn-copy:hover {
      background: #f0f0f0;
      border-color: #999;
    }

    .results-content {
      background: white;
      padding: 10px;
      border-radius: 3px;
      overflow-x: auto;
      font-family: 'Monaco', 'Courier New', monospace;
      font-size: 12px;
      line-height: 1.4;
      color: #333;
      max-height: 400px;
      overflow-y: auto;
      margin: 0;
    }
  `]
})
export class ResultsPanelComponent {
  @Input() result: any;

  formatResults(): string {
    return JSON.stringify(this.result, null, 2);
  }

  copyToClipboard(): void {
    navigator.clipboard.writeText(this.formatResults()).then(() => {
      alert('Results copied to clipboard!');
    }).catch(() => {
      alert('Failed to copy results');
    });
  }
}
